#include <stdio.h>
#include <stdbool.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int n; scanf("%d",&n);
        int nums[20];
        for(int i=0;i<n;++i) scanf("%d",&nums[i]);
        int k; scanf("%d",&k);
        bool dp[2001]={false};
        dp[0]=true;
        for(int i=0;i<n;++i){
            int x=nums[i];
            for(int s=k;s>=x;--s){
                if(dp[s-x]) dp[s]=true;
            }
        }
        printf(dp[k]?"Yes\n":"No\n");
    }
    return 0;
}

