import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        n = int(next(it))
        nums = [int(next(it)) for _ in range(n)]
        k = int(next(it))
        dp = [False] * (k + 1)
        dp[0] = True
        for x in nums:
            for s in range(k, x - 1, -1):
                if dp[s - x]:
                    dp[s] = True
        out.append('Yes' if dp[k] else 'No')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

